// Vérifie que le payload est un Buffer
if (Buffer.isBuffer(msg.payload)) {
    // Convertit chaque octet en hexadécimal sur 2 chiffres
    msg.payload = msg.payload
        .toString('hex')                // Convertit tout le buffer en une chaîne hexadécimale continue
        .match(/.{1,2}/g)               // Coupe la chaîne tous les 2 caractères
        .join(' ') + '\n';              // Ajoute un espace entre chaque octet et un retour à la ligne
} else if (Array.isArray(msg.payload)) {
    // Si c'est un tableau, on le traite aussi
    msg.payload = msg.payload
        .map(x => x.toString(16).padStart(2, '0'))
        .join(' ') + '\n';
} else {
    // Sinon, on ne fait rien ou on peut lever une erreur
    msg.payload = 'Payload non reconnu\n';
}
return msg;

// Récupération des données du payload
const data = msg.payload;

// Fonction pour traiter les champs contenant ":"
function processAddressPortFields(data) {
    const processedData = {...data}; // Copie de l'objet original

    // Liste des champs à traiter (ceux qui peuvent contenir adresse:port)
    const fieldsToProcess = [
        { field: 'gateway_ip_port', addressField: 'gateway_ip', portField: 'gateway_port' },
        { field: 'mqttadresse_port', addressField: 'mqttadresse', portField: 'mqttport' },
        { field: 'cloud_broker_adress_port', addressField: 'cloud_broker_adress', portField: 'cloud_broker_port' }
    ];

    fieldsToProcess.forEach(config => {
        if (processedData[config.field] && typeof processedData[config.field] === 'string') {
            const value = processedData[config.field];

            // Vérifier si le champ contient ":"
            if (value.includes(':')) {
                const lastColonIndex = value.lastIndexOf(':'); // Utilise le dernier ":" pour gérer les IPv6
                const address = value.substring(0, lastColonIndex);
                const port = value.substring(lastColonIndex + 1);

                // Ajouter les champs séparés
                processedData[config.addressField] = address;
                processedData[config.portField] = parseInt(port, 10);

                node.log(`Champ '${config.field}' traité: ${address}:${port}`);
            }

            // Supprimer le champ original avec "_port" 
            delete processedData[config.field];
        }
    });

    return processedData;
}

