const interfaces = msg.payload?.networkInterfaces || {};
let ip = null;
let chosenIf = null;

const ignorePrefixes = ["lo", "docker", "veth", "br-", "hassio"];
const ignoreExact = ["lo", "docker0", "hassio"];

for (const [ifName, entries] of Object.entries(interfaces)) {
    if (
        ignoreExact.includes(ifName) ||
        ignorePrefixes.some(prefix => ifName.startsWith(prefix))
    ) {
        continue;
    }

    for (const entry of entries) {
        if (
            entry.family === "IPv4" &&
            entry.internal === false &&
            entry.address &&
            !entry.address.startsWith("127.") &&
            !entry.address.startsWith("169.254.")
        ) {
            ip = entry.address;
            chosenIf = ifName;
            break;
        }
    }

    if (ip) break;
}

if (!ip) {
    for (const [ifName, entries] of Object.entries(interfaces)) {
        for (const entry of entries) {
            if (
                entry.family === "IPv4" &&
                entry.internal === false &&
                entry.address &&
                !entry.address.startsWith("127.")
            ) {
                ip = entry.address;
                chosenIf = ifName;
                break;
            }
        }
        if (ip) break;
    }
}

