// Fonctions utilitaires
function formatBoolean(val) {
    if (typeof val === 'boolean') return val ? 'True' : 'False';
    const v = String(val).toLowerCase();
    return v === 'true' ? 'True' : v === 'false' ? 'False' : val;
}

function buildDiscoveryMessages(payloadObj) {
    const msgs = [];
    for (const key in payloadObj) {
        if (key === "0x1114") continue; // 🔹 Ignore cette clé

        const cleanKey = key.replace(/_[A-Z]+$/, "").toLowerCase();
        const entityType = key.endsWith("_B") ? "switch" : "number";

        let cfg = {
            name: key.replace(/_[A-Z]+$/, "").replace(/_/g, " "),
            unique_id: `${deviceID}_${cleanKey}`,
            state_topic: `${baseTopic}/control/${cleanKey}/state`,
            command_topic: `${baseTopic}/control/${cleanKey}/set`,
            entity_category: "config",
            device: {
                identifiers: [deviceID],
                name: deviceName,
                manufacturer: "Smartphoton-JK-BMS / ©JLM 2025-2026",
                model: "Setup BMS",
                sw_version: "3.5"
            }
        };

        if (entityType === "number") {
            cfg.mode = "box";
            const bounds = customBounds[key];
            if (bounds) {
                cfg.min = bounds.min; cfg.max = bounds.max; cfg.step = bounds.step;
                if (bounds.unit) cfg.unit_of_measurement = bounds.unit;
            } else {
                // règles par défaut
                if (key.endsWith("_V")) {
                    cfg.unit_of_measurement = "V"; cfg.min = 0; cfg.max = 5; cfg.step = 0.01;
                } else if (key.endsWith("_A")) {
                    cfg.unit_of_measurement = "A"; cfg.min = 0; cfg.max = 400; cfg.step = 0.1;
                } else if (key.endsWith("_S")) {
                    cfg.unit_of_measurement = "s"; cfg.min = 0; cfg.max = 3600; cfg.step = 1;
                } else if (key.endsWith("_T")) {
                    cfg.unit_of_measurement = "°C"; cfg.min = -40; cfg.max = 150; cfg.step = 0.5;
                } else {
                    cfg.min = 0; cfg.max = 100; cfg.step = 1;
                }
            }
        } else if (entityType === "switch") {
            cfg.payload_on = "True"; cfg.payload_off = "False";
            cfg.state_on = "True"; cfg.state_off = "False";
        }

        msgs.push({
            topic: `${discoveryPrefix}/${entityType}/${deviceID}/${cleanKey}/config`,
            payload: JSON.stringify(cfg),
            retain: true
        });
    }
    return msgs;
}

function buildStateMessages(payloadObj) {
    const msgs = [];
    for (const key in payloadObj) {
        if (key === "0x1114") continue; // 🔹 Ignore aussi pour les states

        const cleanKey = key.replace(/_[A-Z]+$/, "").toLowerCase();
        msgs.push({
            topic: `${baseTopic}/control/${cleanKey}/state`,
            payload: formatBoolean(payloadObj[key]),
            retain: true
        });
    }
    return msgs;
}
