const slaveId = global.get("slaveAddress-Trame3") || 0x01;

// Conversion de la valeur hexadécimale en décimal si nécessaire
const slaveIdNumber = typeof slaveId === 'string' ? parseInt(slaveId, 16) : slaveId;

var payload = msg.payload;
var baseTopic = "BMS_" + slaveIdNumber;
var discoveryPrefix = "homeassistant/sensor";
var deviceName = "BMS_" + slaveIdNumber;
var deviceID = "BMS_" + slaveIdNumber + "_device";
