// ------------------------------------------------------------------

// ------------------------------------------------------------------
// 2. Variables de travail
var topics = {};
var discoveryMsgs = [];
var dynamicData = {};

// Clés calculées à ignorer pour le discovery (laissée vide ici)
const excludeFromDiscovery = [];
// ------------------------------------------------------------------

// ------------------------------------------------------------------
// 3. Traitement des tensions de cellules
let configuredCellCount = Number(global.get("jk_cell_count")) || 16;
configuredCellCount = Math.max(1, Math.min(configuredCellCount, 16));

var cellVoltages = [];
var cellKeys = [];

for (let i = 1; i <= configuredCellCount; i++) {
    let key = `Cell_${i}_volt_V`;
    let voltage = Number(payload[key]);
    if (!isNaN(voltage) && voltage > 0) {
        cellVoltages.push(voltage);
        cellKeys.push(key);
    }
}

// Calculs des statistiques des cellules
if (cellVoltages.length > 0) {
    var cellAvgVolt = cellVoltages.reduce((sum, v) => sum + v, 0) / cellVoltages.length;
    var cellMaxVolt = Math.max(...cellVoltages);
    var cellMinVolt = Math.min(...cellVoltages);
    var cellDeltaVolt = cellMaxVolt - cellMinVolt;

    var maxVoltIndex = cellKeys[cellVoltages.indexOf(cellMaxVolt)].match(/Cell_(\d+)/)[1];
    var minVoltIndex = cellKeys[cellVoltages.indexOf(cellMinVolt)].match(/Cell_(\d+)/)[1];

    payload["cell_count_used_N"]       = configuredCellCount;
    payload["cell_voltage_average_V"]  = parseFloat(cellAvgVolt.toFixed(3));
    payload["cell_voltage_delta_V"]    = parseFloat(cellDeltaVolt.toFixed(3));
    payload["cell_voltage_max_number_N"]= parseInt(maxVoltIndex);
    payload["cell_voltage_min_number_N"]= parseInt(minVoltIndex);
    payload["cell_voltage_min_value_V"] = parseFloat(cellMinVolt.toFixed(3));
    payload["cell_voltage_max_value_V"] = parseFloat(cellMaxVolt.toFixed(3));
} else {
    payload["cell_count_used_N"]       = configuredCellCount;
    payload["cell_voltage_average_V"]  = 0;
    payload["cell_voltage_delta_V"]    = 0;
    payload["cell_voltage_max_number_N"]= 0;
    payload["cell_voltage_min_number_N"]= 0;
    payload["cell_voltage_min_value_V"] = 0;
    payload["cell_voltage_max_value_V"] = 0;
}
// ------------------------------------------------------------------
// 3b. Traitement du Total_runtime pour format lisible
if (payload["Total_runtime_S"] !== undefined) {
    var totalSeconds = parseInt(payload["Total_runtime_S"]);
    if (!isNaN(totalSeconds)) {
        var days = Math.floor(totalSeconds / 86400);
        var remainingSeconds = totalSeconds % 86400;
        var hours = Math.floor(remainingSeconds / 3600);
        var minutes = Math.floor((remainingSeconds % 3600) / 60);

        // Création du format 300D22H46M
        payload["Total_runtime_formatted_T"] = `${days}D${hours}H${minutes}M`;
    }
}
// ------------------------------------------------------------------

// ------------------------------------------------------------------
// 3c. Traitement du charge_status_N : conversion en texte lisible
if (payload["charge_status_N"] !== undefined) {
    var statusValue = parseInt(payload["charge_status_N"]);
    var statusText = "Unknown";

    switch(statusValue) {
        case 0:
        case 0x00:
            statusText = "Bulk";
            break;
        case 1:
        case 0x01:
            statusText = "Absorption";
            break;
        case 2:
        case 0x02:
            statusText = "Float";
            break;
    }

    // Création d'une nouvelle clé avec le texte lisible
    payload["charge_status_text_S"] = statusText;
}

// Traitement du charge_status_time_S pour format lisible
if (payload["charge_status_time_S"] !== undefined) {
    var statusSeconds = parseInt(payload["charge_status_time_S"]);
    if (!isNaN(statusSeconds)) {
        var days = Math.floor(statusSeconds / 86400);
        var remainingSeconds = statusSeconds % 86400;
        var hours = Math.floor(remainingSeconds / 3600);
        var minutes = Math.floor((remainingSeconds % 3600) / 60);
        var seconds = remainingSeconds % 60;

        // Création du format lisible
        if (days > 0) {
            payload["charge_status_time_formatted_T"] = `${days}D${hours}H${minutes}M`;
        } else if (hours > 0) {
            payload["charge_status_time_formatted_T"] = `${hours}H${minutes}M${seconds}S`;
        } else if (minutes > 0) {
            payload["charge_status_time_formatted_T"] = `${minutes}M${seconds}S`;
        } else {
            payload["charge_status_time_formatted_T"] = `${seconds}S`;
        }
    }
}
// ------------------------------------------------------------------

// ------------------------------------------------------------------
// 4. Création des messages de données et (si besoin) de discovery
const allowedSuffixes = ["_V", "_A", "_W", "_T", "_Ah", "_R", "_P", "_S", "_B", "_N"];

for (var key in payload) {
    if (excludeFromDiscovery.includes(key)) continue;

    var hasValidSuffix = allowedSuffixes.some(s => key.endsWith(s));
    if (!hasValidSuffix) continue;

    var cleanKey = key.replace(/_[A-Z]+$/, "");
    var sensorTopic = `${baseTopic}/${cleanKey}`;
    topics[sensorTopic] = payload[key];
    dynamicData[cleanKey] = payload[key];

    if (!discoveryAlreadySent) {
        var configTopic = `${discoveryPrefix}/${deviceID}_${cleanKey}/config`;
        var configPayload = {
            name: cleanKey,
            unique_id: `${deviceID}_${cleanKey}`,
            state_topic: sensorTopic,
            unit_of_measurement: "",
            entity_category: "diagnostic",
            device: {
                identifiers: [deviceID],
                name: deviceName,
                manufacturer: "Smartphoton-JK-BMS / ©JLM 2025-2026",
                model: payload.BMS_A || "rs485 vers MQTT",
                sw_version: payload.SW_N || "3.5"
            }
        };

        if (key.endsWith("_V")) configPayload.unit_of_measurement = "V";
        else if (key.endsWith("_Ah")) configPayload.unit_of_measurement = "Ah";
        else if (key.endsWith("_A")) configPayload.unit_of_measurement = "A";
        else if (key.endsWith("_W")) configPayload.unit_of_measurement = "W";
        else if (key.endsWith("_T")) {
            // Pour les temps formatés, pas d'unité car c'est déjà dans le format
            if (key === "Total_runtime_formatted_T" || key === "charge_status_time_formatted_T") {
                configPayload.unit_of_measurement = "";
                configPayload.icon = "mdi:clock-time-eight-outline";
            } 
            // Autres cas avec _T = température
            else {
                configPayload.unit_of_measurement = "°C";
            }
        }
        else if (key.endsWith("_R")) configPayload.unit_of_measurement = "Ω";
        else if (key.endsWith("_P")) {
            configPayload.unit_of_measurement = "%";
            if (key.startsWith("SOC")) configPayload.device_class = "battery";
        } 
        else if (key.endsWith("_S")) {
            // Pour charge_status_text_S, c'est du texte sans unité
            if (key === "charge_status_text_S") {
                configPayload.unit_of_measurement = "";
                configPayload.icon = "mdi:battery-charging";
            } 
            // Pour charge_status_time_S, unité en secondes avec icône timer
            else if (key === "charge_status_time_S") {
                configPayload.unit_of_measurement = "s";
                configPayload.icon = "mdi:timer-outline";
            }
            // Autres cas avec _S = secondes par défaut
            else {
                configPayload.unit_of_measurement = "s";
            }
        }

        discoveryMsgs.push({ topic: configTopic, payload: JSON.stringify(configPayload), retain: true });
    }
}

// Ajouter les clés calculées aux données dynamiques (sans discovery)
[
    "cell_voltage_average_V",
    "cell_voltage_delta_V",
    "cell_voltage_max_number_N",
