}

return [outputMsgs];

// Vérifier que nous avons reçu des données
if (!msg.payload || msg.payload.length < 7) {
    node.warn("Pas de données reçues ou données incomplètes");
    return null;
}

const response = msg.payload;

// Structure de la réponse Modbus :
// [0] = Slave ID
// [1] = Function Code (0x03)
// [2] = Byte Count (devrait être 2)
// [3] = RCVTime (Premier byte - Request Charge Voltage Time)
// [4] = RFVTime (Deuxième byte - Request Float Voltage Time)
// [5-6] = CRC

const slaveId = response[0];
const functionCode = response[1];
const byteCount = response[2];
const RCVTime_raw = response[3];  // Premier byte
const RFVTime_raw = response[4];  // Deuxième byte

// Conversion avec l'unité 0.1H (diviser par 10 pour obtenir des heures)
const RCVTime_hours = RCVTime_raw * 0.1;
const RFVTime_hours = RFVTime_raw * 0.1;

// Préparer le message de sortie
msg.payload = {
    address: "0x1104",
    slaveId: slaveId,
    functionCode: functionCode,
    raw_response: response,
    RCVTime: {
        raw: RCVTime_raw,
        value: RCVTime_hours,
        unit: "h",
        description: "Request Charge Voltage Time"
    },
    RFVTime: {
        raw: RFVTime_raw,
        value: RFVTime_hours,
        unit: "h",
        description: "Request Float Voltage Time"
    }
};

// Message de debug formaté
node.status({
    fill: "green",
    shape: "dot",
    text: `RCVTime: ${RCVTime_hours}h | RFVTime: ${RFVTime_hours}h`
});

node.warn(`Lecture 0x1104 - RCVTime: ${RCVTime_hours}h (raw: ${RCVTime_raw}) | RFVTime: ${RFVTime_hours}h (raw: ${RFVTime_raw})`);

return msg;

// Décodage de la réponse et modification de la valeur appropriée
if (!msg.payload || msg.payload.length < 7) {
    node.warn("Pas de données reçues ou données incomplètes");
    return null;
}

const response = msg.payload;

// Extraction des valeurs actuelles
const currentRCVTime_raw = response[3];  // Premier byte
const currentRFVTime_raw = response[4];  // Deuxième byte

node.warn(`Valeurs actuelles lues - RCVTime: ${currentRCVTime_raw} | RFVTime: ${currentRFVTime_raw}`);

// Récupérer quelle valeur doit être modifiée
const fieldToUpdate = flow.get("field_to_update");
let newRCVTime_raw = currentRCVTime_raw;
let newRFVTime_raw = currentRFVTime_raw;

// Appliquer la modification
if (fieldToUpdate === "RCVTime") {
    const newValue = flow.get("new_RCVTime");
    newRCVTime_raw = Math.round(newValue * 10);
    node.warn(`Modification RCVTime: ${currentRCVTime_raw} -> ${newRCVTime_raw} (${newValue}h)`);
} else if (fieldToUpdate === "RFVTime") {
    const newValue = flow.get("new_RFVTime");
    newRFVTime_raw = Math.round(newValue * 10);
    node.warn(`Modification RFVTime: ${currentRFVTime_raw} -> ${newRFVTime_raw} (${newValue}h)`);
} else {
    node.error("Champ à modifier non défini");
    return null;
}

// Validation
if (newRCVTime_raw < 0 || newRCVTime_raw > 100 || newRFVTime_raw < 0 || newRFVTime_raw > 100) {
    node.error("Valeurs hors limites (0-10h)");
    return null;
}

// Passer les nouvelles valeurs au nœud suivant
msg.payload = {
    RCVTime: newRCVTime_raw,
    RFVTime: newRFVTime_raw
};

return msg;

// Génération de la trame d'écriture Modbus avec les nouvelles valeurs
const slaveId = global.get("slaveAddress-Trame1") || 0x01;
const rcvRaw = msg.payload.RCVTime;
const rfvRaw = msg.payload.RFVTime;

// Calculer CRC16 Modbus
function crc16(buffer) {
    let crc = 0xFFFF;
    for (let i = 0; i < buffer.length; i++) {
        crc ^= buffer[i];
        for (let j = 0; j < 8; j++) {
            if (crc & 0x0001) {
                crc = (crc >> 1) ^ 0xA001;
            } else {
                crc = crc >> 1;
            }
        }
    }
    return crc;
}

// Construction de la trame sans CRC
const dataBuffer = Buffer.from([
    slaveId,
    0x06,           // Function code (Write Single Register)
    0x15,           // Register address high byte
    0x04,           // Register address low byte
    rcvRaw & 0xFF,  // Value high byte (RCVTime)
    rfvRaw & 0xFF   // Value low byte (RFVTime)
]);

// Calcul du CRC
const crc = crc16(dataBuffer);

// Buffer final avec CRC
const finalBuffer = Buffer.allocUnsafe(dataBuffer.length + 2);
dataBuffer.copy(finalBuffer);
finalBuffer.writeUInt16LE(crc, dataBuffer.length);

node.warn(`Écriture registre 0x1504 - RCVTime: ${rcvRaw} | RFVTime: ${rfvRaw}`);

msg.topic = "write_voltage_times";
msg.payload = finalBuffer;
return msg;

// Récupération de l'adresse esclave depuis le contexte global
const slaveId = global.get("slaveAddress-Trame1") || 0x01; // Valeur par défaut si non définie
const functionCode = 0x03; // Function Code 3 : Read Holding Registers
const registerHigh = 0x15; // Adresse haute de 0x1504
const registerLow = 0x04;  // Adresse basse de 0x1504
const quantityHigh = 0x00; // Nombre de registres haute (0x0001 = 1 registre)
const quantityLow = 0x01;  // Nombre de registres basse

// Calculer CRC16 Modbus
function crc16(buffer) {
    let crc = 0xFFFF;
    for (let i = 0; i < buffer.length; i++) {
        crc ^= buffer[i];
        for (let j = 0; j < 8; j++) {
            if (crc & 0x0001) {
                crc = (crc >> 1) ^ 0xA001;
            } else {
                crc = crc >> 1;
            }
        }
    }
    return crc;
}

// Construction du buffer sans CRC
const dataBuffer = Buffer.from([
    slaveId,
    functionCode,
    registerHigh,
    registerLow,
    quantityHigh,
    quantityLow
]);

// Calcul du CRC
const crc = crc16(dataBuffer);

// Buffer final avec CRC
const finalBuffer = Buffer.allocUnsafe(dataBuffer.length + 2);
dataBuffer.copy(finalBuffer);
finalBuffer.writeUInt16LE(crc, dataBuffer.length);

msg.topic = "Trame-1-statiques";
msg.payload = finalBuffer;
return msg;

