// Définition des bits d'alarme (0-23)
const ALARM_BITS = {
    0: "Balancing resistance too high",
    1: "MOS over-temperature protection",
    2: "Number of cells does not match parameter",
    3: "Abnormal current sensor",
    4: "Cell over-voltage protection",
    5: "Battery over-voltage protection",
    6: "Overcurrent charge protection",
    7: "Charge short-circuit protection",
    8: "Over-temperature charge protection",
    9: "Low temperature charge protection",
    10: "Internal communication anomaly",
    11: "Cell under-voltage protection",
    12: "Battery under-voltage protection",
    13: "Overcurrent discharge protection",
    14: "Discharge short-circuit protection",
    15: "Over-temperature discharge protection",
    16: "Charge MOS anomaly",
    17: "Discharge MOS anomaly",
    18: "GPS disconnected",
    19: "Please modify the authorization password in time",
    20: "Discharge activation failure",
    21: "Battery over-temperature alarm",
    22: "Temperature sensor anomaly",
    23: "Parallel module anomaly"
};

// Vérifier que c'est bien une réponse de lecture d'alarmes
if (msg.topic !== "Trame-Alarmes-BMS") {
    return null;
}

// Vérifier que la réponse est un buffer et a suffisamment de données
// Format attendu: [SlaveID][FC][ByteCount][Data...][CRC_L][CRC_H]
if (!Buffer.isBuffer(msg.payload) || msg.payload.length < 7) {
    node.error("Réponse invalide: buffer trop court ou format incorrect");
    return null;
}

// Extraction des données Modbus
const slaveId = msg.payload[0];
const functionCode = msg.payload[1];
const byteCount = msg.payload[2];

// Vérification du nombre d'octets (devrait être 4 pour 2 registres)
if (byteCount !== 4) {
    node.error(`Nombre d'octets incorrect: ${byteCount}, attendu: 4`);
    return null;
}

// Extraction de la valeur UINT32 (Big Endian)
// Les 4 octets de données commencent à l'index 3
const alarmValue = msg.payload.readUInt32BE(3);

// Extraire les alarmes actives (bits à 1)
const activeAlarms = [];
const alarmDetails = {};
const alarmBits = [];

for (let bit = 0; bit <= 23; bit++) {
    if (alarmValue & (1 << bit)) {
        const alarmDescription = ALARM_BITS[bit];
        activeAlarms.push({
            bit: bit,
            description: alarmDescription
        });
        alarmDetails[`BIT${bit}`] = alarmDescription;
        alarmBits.push(bit);
    }
}

// Toujours remplir le champ "status"
if (activeAlarms.length === 0) {
    alarmDetails.status = "No BMS alarms";
} else {
    alarmDetails.status = "🚨 BMS Alarm Alert";
}

// Préparer le payload détaillé dans msg.alarms
