    node.warn(`⚠️ BMS #${msg.bmsId || slaveId}: ${activeAlarms.length} alarme(s) active(s) détectée(s)`);
    activeAlarms.forEach(alarm => {
        node.warn(`  - BIT${alarm.bit}: ${alarm.description}`);
    });
}

