// ========== FONCTION 1: LECTURE DES ALARMES JK-BMS ==========
// Lecture de l'adresse 0x12A0 (4778 en décimal) - Registre des alarmes
// UINT32 sur 4 registres (nous allons lire 2 registres de 16 bits)

// Récupération de l'adresse esclave depuis le contexte global
const slaveId = global.get("slaveAddress-Trame3") || 0x01;

// Configuration Modbus pour lecture des alarmes
const functionCode = 0x03;      // FC3: Read Holding Registers
const address = 0x12A0;         // Adresse du registre des alarmes (4778)
const registerHigh = (address >> 8) & 0xFF;   // 0x12
const registerLow = address & 0xFF;            // 0xA0
const quantityHigh = 0x00;
const quantityLow = 0x02;       // Lire 2 registres (32 bits)

// Calculer CRC16 Modbus
function crc16(buffer) {
    let crc = 0xFFFF;
    for (let i = 0; i < buffer.length; i++) {
        crc ^= buffer[i];
        for (let j = 0; j < 8; j++) {
            if (crc & 0x0001) {
                crc = (crc >> 1) ^ 0xA001;
            } else {
                crc = crc >> 1;
            }
        }
    }
    return crc;
}

// Construction du buffer sans CRC
const dataBuffer = Buffer.from([
    slaveId,
    functionCode,
    registerHigh,
    registerLow,
    quantityHigh,
    quantityLow
]);

// Calcul du CRC
const crc = crc16(dataBuffer);

// Buffer final avec CRC
const finalBuffer = Buffer.allocUnsafe(dataBuffer.length + 2);
dataBuffer.copy(finalBuffer);
finalBuffer.writeUInt16LE(crc, dataBuffer.length);

// Topic pour identifier cette requête dans le switch
msg.topic = "Trame-Alarmes-BMS";
