const TIMEOUT_MS   = 120000;
const MAX_FAILOVER = 4; // 2 allers-retours max

if (global.get('use_gateway') !== true) return null;

// Abandon si gateway déclarée injoignable
if (flow.get('gateway_status_master') === 'unreachable') return null;

const last       = flow.get('lastDataTs_master') || 0;
const failoverTs = flow.get('failoverTs_master') || 0;

if (last === 0 && failoverTs === 0) return null;

const ref     = last > 0 ? last : failoverTs;
const elapsed = Date.now() - ref;

if (elapsed <= TIMEOUT_MS) return null;

const count   = (flow.get('failoverCount_master') || 0) + 1;
const current = flow.get('gateway_tcp_slot') || 'A';
const next    = current === 'A' ? 'B' : 'A';

if (count >= MAX_FAILOVER) {
    flow.set('gateway_status_master', 'unreachable');
    flow.set('failoverCount_master', count);
    node.warn(`Gateway master: aucune réponse après ${count} basculements → abandon`);
    return [{ payload: { status: 'unreachable', attempts: count } }];
}

flow.set('gateway_tcp_slot', next);
flow.set('gateway_status_master', 'failover');
flow.set('lastDataTs_master', 0);
flow.set('failoverTs_master', Date.now());
flow.set('failoverCount_master', count);

node.warn(`Gateway watchdog: timeout ${Math.round(elapsed/1000)}s -> failover ${current} => ${next} (tentative ${count}/${MAX_FAILOVER})`);
return [{ payload: { status: 'failover', from: current, to: next, elapsed_s: Math.round(elapsed/1000), attempt: count } }];

// Node-RED function node pour générer la trame Modbus d'écriture
// Entrée attendue: msg.payload contient la tension (ex: 3.42)
function generateModbusWriteCommand(voltage) {
    // Fonction de calcul CRC16 Modbus
    function crc16(buffer) {
        let crc = 0xFFFF;
        for (let i = 0; i < buffer.length; i++) {
            crc ^= buffer[i];
            for (let j = 0; j < 8; j++) {
                if (crc & 0x0001) {
                    crc = (crc >> 1) ^ 0xA001;
                } else {
                    crc = crc >> 1;
                }
            }
        }
        return crc;
    }

    // Conversion de la tension en valeur entière (échelle 1/1000)
    const voltageValue = Math.round(voltage * 1000);

    // Construction de la trame sans CRC
    // Récupération de l'adresse esclave depuis le contexte global
    const slaveId = global.get("slaveAddress-setup") || 0x01; // Valeur par défaut si non définie

    const command = [
        slaveId,                           // Slave ID
        0x10,                           // Function code (16/0x10 - Write Multiple Registers)
        0x10,                           // Register address high byte (0x10)
        0x84,                           // Register address low byte (0x84)
        0x00,                           // Quantity high byte (2 registres pour uint32)
        0x02,                           // Quantity low byte (2 registres pour uint32)
        0x04,                           // Byte count (4 bytes pour uint32)
        (voltageValue >> 24) & 0xFF,    // Valeur MSB (premier octet)
        (voltageValue >> 16) & 0xFF,    // Deuxième octet
        (voltageValue >> 8) & 0xFF,     // Troisième octet
        voltageValue & 0xFF             // Valeur LSB (dernier octet)
    ];

    // Calcul du CRC
    const crc = crc16(Buffer.from(command));

    // Ajout du CRC à la trame (en ordre inverse car little-endian)
    command.push(crc & 0xFF);          // CRC low byte
    command.push((crc >> 8) & 0xFF);   // CRC high byte

    return Buffer.from(command);
}

