    function crc16(buffer) {
        let crc = 0xFFFF;
        for (let i = 0; i < buffer.length; i++) {
            crc ^= buffer[i];
            for (let j = 0; j < 8; j++) {
                if (crc & 0x0001) {
                    crc = (crc >> 1) ^ 0xA001;
                } else {
                    crc = crc >> 1;
                }
            }
        }
        return crc;
    }

    // Conversion de l'entrée en booléen
    let isOn = false;
    if (typeof input === 'string') {
        isOn = input.toLowerCase() === 'true';
    } else if (typeof input === 'boolean') {
        isOn = input;
    }

    // Debug
    console.log("Input value:", input);
    console.log("Converted to:", isOn);

    // Construction de la trame sans CRC
    // Récupération de l'adresse esclave depuis le contexte global
    const slaveId = global.get("slaveAddress-setup") || 0x01; // Valeur par défaut si non définie

