// DÉTERMINATION DU BMS (master / esclave)
let bmsName;
let bmsId;

if (msg.bms_numero === 0) {
    bmsName = "BMS_master";
    bmsId = 0;
} else {
    bmsId = msg.bms_numero;
    bmsName = `BMS_${bmsId}`;
}

// ------------------------------------------------------------------
// CLÉS DE STOCKAGE POUR DÉTECTION DE CHANGEMENT
