// CONVERSION AU FORMAT INTERNE
const hasAlarms = p.error_code !== 0;
const alarmCount = (p.errors && hasAlarms) ? p.errors.length : 0;

const alarmData = {
    bms_id: bmsId,
    has_alarms: hasAlarms,
    alarm_count: alarmCount,
    active_alarms: (p.errors && hasAlarms)
        ? p.errors.map(e => ({ description: e }))
        : [],
    alarm_details: {
        status: hasAlarms
            ? "🚨 BMS Alarm Alert"
            : "No BMS alarms"
    }
};

// ------------------------------------------------------------------
// DÉTECTION DE CHANGEMENT
// On crée une signature de l'état actuel pour comparaison
const currentStateSignature = JSON.stringify({
    error_code: p.error_code,
    errors: p.errors || []
});

const hasChanged = (lastAlarmState !== currentStateSignature);

