// Diag Serial Snapshot
// Déclenché toutes les 30 secondes par un inject

const now = Date.now();
const WINDOW_MS = 120 * 1000;

let s = flow.get("diag_serial_stats") || {
    first_ts: now,
    last_serial_rx_ts: 0,
    buffers_30s: 0,
    bytes_30s: 0,
    short_buffers_30s: 0,
    multi_header_buffers_30s: 0,
    frame_candidates_30s: 0,
    frames_emitted_30s: 0,
    emitted_frame_bytes_30s: 0,
    last_len: 0,
    sum_len_30s: 0,
    max_len_30s: 0,
    transport: "unknown",
    detected_bms_seen: {},
    detected_bms: 0,
    detected_bms_list: ""
};

let seen = s.detected_bms_seen || {};
for (const [id, ts] of Object.entries(seen)) {
    if ((now - ts) > WINDOW_MS) {
        delete seen[id];
    }
}

const detectedList = Object.keys(seen).sort((a, b) => {
    if (a === "master") return -1;
    if (b === "master") return 1;
    const na = Number(a), nb = Number(b);
    if (Number.isFinite(na) && Number.isFinite(nb)) return na - nb;
    return String(a).localeCompare(String(b));
});

s.detected_bms_seen = seen;
s.detected_bms = detectedList.length;
s.detected_bms_list = detectedList.join(", ");

const serialAge = s.last_serial_rx_ts ? Number(((now - s.last_serial_rx_ts) / 1000).toFixed(3)) : null;
const avgLen = s.buffers_30s ? Math.round(s.sum_len_30s / s.buffers_30s) : 0;
const bytesPerBufferAvg = avgLen;
const framesEmitted = s.frames_emitted_30s || 0;
const emittedFrameBytes = s.emitted_frame_bytes_30s || 0;
const frameYieldRatio = s.frame_candidates_30s > 0
    ? Number((framesEmitted / s.frame_candidates_30s).toFixed(2))
    : 0;
const avgFrameLen = framesEmitted > 0
    ? Math.round(emittedFrameBytes / framesEmitted)
    : 0;

let status = "starting";
let health_reason = "waiting_for_serial_data";
let health_flags = [];

if (serialAge !== null) {
    if (serialAge >= 30) {
        status = "no_serial_data";
        health_reason = "serial_timeout";
        health_flags.push("serial_stale");
    } else if (serialAge >= 10) {
        status = "degraded";
        health_reason = "serial_slow";
        health_flags.push("serial_slow");
    } else {
        status = "healthy";
        health_reason = "healthy";
    }

    if (s.buffers_30s > 0 && bytesPerBufferAvg < 35) {
        if (status === "healthy") status = "degraded";
        health_reason = "excessive_fragmentation";
        health_flags.push("low_avg_buffer_len");
    }

    if (s.frame_candidates_30s > 0 && framesEmitted === 0) {
        if (status === "healthy") status = "degraded";
        health_reason = "no_valid_frames_emitted";
        health_flags.push("parser_no_output");
    } else if (s.frame_candidates_30s >= 10 && frameYieldRatio < 0.50) {
        if (status === "healthy") status = "degraded";
        health_reason = "low_frame_yield";
        health_flags.push("low_frame_yield");
    }

    if (s.multi_header_buffers_30s > 40) {
        if (status === "healthy") {
            health_reason = "healthy_multi_bms_broadcast_concat";
        }
        health_flags.push("high_multi_header_concat");
    }

    if (
        status === "healthy" &&
        s.transport === "serial" &&
        s.buffers_30s >= 40 &&
        bytesPerBufferAvg >= 80 &&
        bytesPerBufferAvg <= 190 &&
        frameYieldRatio >= 0.70 &&
        serialAge < 0.5
    ) {
        health_reason = s.detected_bms >= 2 ? "healthy_multi_bms_broadcast" : "healthy";
    }

    if (
        status === "healthy" &&
        s.transport === "serial" &&
        s.short_buffers_30s > 0 &&
        s.short_buffers_30s >= Math.round(s.buffers_30s * 0.75)
    ) {
        health_flags.push("many_short_buffers");
    }
}

const health_flags_text = health_flags.length ? health_flags.join(", ") : "none";

msg.topic = "BMS_GLOBAL/health";
