    health_flags,
    health_flags_text,
    serial_age_s: serialAge,
    buffers_30s: s.buffers_30s,
    frame_candidates_30s: s.frame_candidates_30s,
    frames_emitted_30s: framesEmitted,
    frame_yield_ratio: frameYieldRatio,
    short_buffers_30s: s.short_buffers_30s,
    multi_header_buffers_30s: s.multi_header_buffers_30s,
    last_len: s.last_len,
    avg_len_30s: avgLen,
    bytes_per_buffer_avg_30s: bytesPerBufferAvg,
    max_len_30s: s.max_len_30s,
    bytes_30s: s.bytes_30s,
    emitted_frame_bytes_30s: emittedFrameBytes,
    avg_frame_len_30s: avgFrameLen,
    transport: s.transport || "unknown",
