        frames_emitted_30s: 0,
        emitted_frame_bytes_30s: 0,
        last_len: 0,
        sum_len_30s: 0,
        max_len_30s: 0,
        transport: "unknown",
        detected_bms_seen: {},
        detected_bms: 0,
        detected_bms_list: ""
    };

    s.frames_emitted_30s = (s.frames_emitted_30s || 0) + frames.length;
    s.emitted_frame_bytes_30s = (s.emitted_frame_bytes_30s || 0) + frames.reduce((acc, f) => acc + ((f && f.payload && f.payload.length) ? f.payload.length : 0), 0);
    flow.set("diag_serial_stats", s);

    return [frames.map(f => ({ payload: f }))];
}

return null;

