    s.buffers_30s += 1;
    s.bytes_30s += len;
    s.last_len = len;
    s.sum_len_30s += len;
    s.max_len_30s = Math.max(s.max_len_30s, len);

    if (len < 20) {
        s.short_buffers_30s += 1;
    }

    // Heuristiques simples pour repérer les signatures de trames
    let headerCount = 0;

    for (let i = 0; i < buf.length - 3; i++) {
        // header JK
        if (
            buf[i] === 0x55 &&
            buf[i + 1] === 0xAA &&
            buf[i + 2] === 0xEB &&
            buf[i + 3] === 0x90
        ) {
            headerCount++;
        }

        // début plausible Modbus
        if (
            i < buf.length - 4 &&
            buf[i] >= 0x01 && buf[i] <= 0x0F &&
            buf[i + 1] === 0x10 &&
            buf[i + 2] === 0x16 &&
            (buf[i + 3] === 0x20 || buf[i + 3] === 0x1E)
        ) {
            headerCount++;
        }
    }

    if (headerCount > 0) {
        s.frame_candidates_30s += 1;
    }
    if (headerCount > 1) {
        s.multi_header_buffers_30s += 1;
    }
}

flow.set("diag_serial_stats", s);

return msg;

if (Buffer.isBuffer(msg.payload)) {
    msg.payload = msg.payload.toString("hex");
}
return msg;

// Vérifie que le payload est un Buffer
if (Buffer.isBuffer(msg.payload)) {
    // Convertit chaque octet en hexadécimal sur 2 chiffres
    msg.payload = msg.payload
        .toString('hex')                // Convertit tout le buffer en une chaîne hexadécimale continue
        .match(/.{1,2}/g)               // Coupe la chaîne tous les 2 caractères
        .join(' ') + '\n';              // Ajoute un espace entre chaque octet et un retour à la ligne
} else if (Array.isArray(msg.payload)) {
    // Si c'est un tableau, on le traite aussi
    msg.payload = msg.payload
        .map(x => x.toString(16).padStart(2, '0'))
        .join(' ') + '\n';
} else {
    // Sinon, on ne fait rien ou on peut lever une erreur
    msg.payload = 'Payload non reconnu\n';
}
