// - esclaves => discoverySent_BMS_1 ... discoverySent_BMS_N

let totalBms = parseInt(global.get("nb_jkbms"), 10);

// Fallback de sécurité
if (isNaN(totalBms) || totalBms < 0) {
    totalBms = 4;
