let p = msg.payload || {};
let bmsAdresse = msg.bms_numero;
let slaveIdStr;

if (typeof bmsAdresse === "string" && bmsAdresse.toLowerCase() === "master") {
    slaveIdStr = "master";
} else if (!isNaN(Number(bmsAdresse))) {
