                model: "JK-BMS - RS485",
                sw_version: "3.5"
            }
        };

        // Gestion des unités
        if (key.endsWith("_V")) configPayload.unit_of_measurement = "V";
        else if (key.endsWith("_Ah")) configPayload.unit_of_measurement = "Ah";
        else if (key.endsWith("_A")) configPayload.unit_of_measurement = "A";
        else if (key.endsWith("_W")) configPayload.unit_of_measurement = "W";
        else if (key.endsWith("_R")) configPayload.unit_of_measurement = "Ω";
        else if (key.endsWith("_P")) {
            configPayload.unit_of_measurement = "%";
            if (key.startsWith("SOC")) configPayload.device_class = "battery";
        }
        // --- BOOLÉENS (_B) : CONFIGURATION COMPLÈTE ---
        else if (key.endsWith("_B")) {
            configPayload.unit_of_measurement = "";
            configPayload.icon = "mdi:toggle-switch";

            if (key === "Heating_B") {
                configPayload.device_class = "heat";
                configPayload.icon = "mdi:heating-coil";
            } else if (key === "Switch_Charge_B") {
                configPayload.icon = "mdi:battery-charging";
            } else if (key === "Switch_Decharge_B") {
                configPayload.icon = "mdi:battery-minus";
            } else if (key === "Balance_Action_B") {
                configPayload.icon = "mdi:battery-sync";
            } else if (key === "Switch_Balance_B") {
                configPayload.icon = "mdi:battery-balance";
            }
        }
        // --- TEMPS (_T) ---
        else if (key.endsWith("_T")) {
            if (key === "Total_runtime_formatted_T" ||
                key === "charge_status_time_formatted_T") {
                configPayload.unit_of_measurement = "";
                configPayload.icon = "mdi:clock-time-eight-outline";
            } else {
                configPayload.unit_of_measurement = "°C";
            }
        }
        // --- TEXTE (_S) ---
        else if (key.endsWith("_S")) {
            if (key === "charge_status_text_S") {
                configPayload.unit_of_measurement = "";
                configPayload.icon = "mdi:battery-charging";
            } 
            else if (key === "Heating_status_text_S") {
                configPayload.unit_of_measurement = "";
                configPayload.icon = "mdi:heating-coil";
            }
            else if (key === "charge_status_time_S") {
                configPayload.unit_of_measurement = "s";
                configPayload.icon = "mdi:timer-outline";
            } 
            else {
                configPayload.unit_of_measurement = "s";
            }
        }
        // --- NOMBRES (_N) ---
        else if (key.endsWith("_N")) {
            configPayload.unit_of_measurement = "";
            configPayload.icon = "mdi:counter";
        }

        discoveryMsgs.push({
            topic: configTopic,
            payload: JSON.stringify(configPayload),
